sql_query:
SELECT "Is PD-L1 positivity inclusion criteria"
FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck';

ground_truth_sql:
WITH base AS (
SELECT "NCT", "PubMed ID", "Trial name", "Is PD-L1 positivity inclusion criteria" AS source_value FROM clinical_trials
WHERE "Cancer type" = 'Head and Neck'
)
SELECT "NCT", "PubMed ID", "Trial name", source_value, derive_pd_l1_required(source_value) AS "pd_l1_required"
FROM base;
